const galleryData=[{id:101,src:"images/黄山/IMG_20250402_073324.jpg",category:"huangshan",title:"黄山迎客松",description:"黄山标志性景观迎客松"},{id:102,src:"images/黄山/IMG_20250402_074608.jpg",category:"huangshan",title:"云海奇观",description:"黄山四大奇观之一的云海"},{id:103,src:"images/黄山/IMG_20250402_080852.jpg",category:"huangshan",title:"光明顶日出",description:"在黄山第二高峰光明顶观看日出"},{id:104,src:"images/黄山/IMG_20250402_093050.jpg",category:"huangshan",title:"奇石怪峰",description:"黄山的奇石景观"},{id:105,src:"images/黄山/IMG_20250402_093600.jpg",category:"huangshan",title:"西海大峡谷",description:"黄山最壮观的峡谷之一"},{id:106,src:"images/黄山/IMG_20250402_100122.jpg",category:"huangshan",title:"温泉景区",description:"黄山温泉，古称'朱砂泉'"}];
let currentImageIndex=0,currentFilter='all';
function renderGallery(filter){currentFilter=filter;const e=document.getElementById("photoGallery");if(!e)return;e.innerHTML="";const t="all"===filter?galleryData:galleryData.filter(e=>e.category===filter);t.forEach((filter,e)=>{const t=document.createElement("div");t.className="gallery-item",t.setAttribute("data-category",filter.category),t.setAttribute("data-index",e),t.innerHTML='<img src="'+filter.src+'" alt="'+filter.title+'" loading="lazy"><div class="gallery-caption"><h4>'+filter.title+'</h4><p>'+filter.description+"</p></div>",t.addEventListener("click",()=>openImageViewer(e,filter)),document.getElementById("photoGallery").appendChild(t)})}function filterGallery(e){renderGallery(e);const t=document.querySelector(".gallery-grid");t&&t.scrollIntoView({behavior:"smooth",block:"start"})}function openImageViewer(e,t){const a="all"===t?galleryData:galleryData.filter(a=>a.category===t);currentImageIndex=e;const o=a[e],n=document.getElementById("imageViewer"),d=document.getElementById("viewerImage"),r=document.getElementById("imageCaption");n&&d&&r&&(d.src=o.src,d.alt=o.title,r.innerHTML='<h3>'+o.title+'</h3><p>'+o.description+"</p>",n.style.display="flex",document.body.style.overflow="hidden")}function closeImageViewer(){const e=document.getElementById("imageViewer");e&&(e.style.display="none",document.body.style.overflow="auto")}function prevImage(){const e="all"===currentFilter?galleryData:galleryData.filter(e=>e.category===currentFilter);currentImageIndex=(currentImageIndex-1+e.length)%e.length;const t=e[currentImageIndex],a=document.getElementById("viewerImage"),o=document.getElementById("imageCaption");a&&o&&(a.src=t.src,a.alt=t.title,o.innerHTML='<h3>'+t.title+'</h3><p>'+t.description+"</p>")}function nextImage(){const e="all"===currentFilter?galleryData:galleryData.filter(e=>e.category===currentFilter);currentImageIndex=(currentImageIndex+1)%e.length;const t=e[currentImageIndex],a=document.getElementById("viewerImage"),o=document.getElementById("imageCaption");a&&o&&(a.src=t.src,a.alt=t.title,o.innerHTML='<h3>'+t.title+'</h3><p>'+t.description+"</p>")}document.addEventListener("DOMContentLoaded",function(){renderGallery("all")});